export function parseArgs(argv) {
  const result = { _: [] }
  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
    } else if (arg.endsWith('=') || arg.includes('=')) {
      result[arg.slice(2).split('=')[0]] = arg.slice(arg.indexOf('=') + 1)
      i++
    } else {
      const name = arg.slice(2)
      const next = argv[i + 1]
      if (next && !next.startsWith('-') && !next.includes('=')) {
        result[name] = next
        i++
      } else {
        result[name] = true
      }
    }
  }
  return result
}

